import type { WithRef } from '@andes/common';
import type {
  FunctionComponent,
  ReactElement,
  MouseEvent,
  KeyboardEvent,
} from 'react';
import type { ListProps } from '@andes/list';

type ListBoxProps = WithRef<HTMLUListElement> & {
  /**
   * Indicates the children of the component.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  children: Array<ReactElement> | ReactElement;

  /**
   * Adds a custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  className?: string;

  /**
   * Selectable list's initial set of values (uncontrolled behavior).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  defaultSelectedKeys?: Array<string>;

  /**
   * Selectable list unique Id, used for a11y improvements.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  id: string;

  /**
   * Allows single or multiple item selection.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   * @default 'single'
   */
  selectionMode?: 'multiple' | 'single';

  /**
   * Whether the listbox items should use virtual focus instead of being focused directly.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  shouldUseVirtualFocus?: boolean;

  /**
   * Function to execute when an option is clicked.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  onClick?: (
    event: KeyboardEvent<HTMLLIElement> | MouseEvent<HTMLLIElement>,
    itemValue?: string,
  ) => void;

  /**
   * Function to execute when an option is selected/unselected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  onSelect?: (
    event: KeyboardEvent<HTMLLIElement> | MouseEvent<HTMLLIElement>,
    selectedValues: Array<string>,
    itemDetails: { value: string },
  ) => void;

  /**
   * ListBox label for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  srLabel?: string;

  /**
   * Determines if the listbox is radio list or not.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   * @default false
   */
  isRadioList?: boolean;

  /**
   * Selectable list's initial set of values (controlled behavior).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  selectedKeys?: Array<string>;

  /**
   * Custom element that will act as a selector in the list.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/README.md#listbox | Documentation}
   */
  selectionComponent?: ReactElement;
};

/**
 * ListBox presents a list of options and allows a user to select one or more of them.
 * This is an internal component, if you need to use it please contact us to follow the use case.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/listbox | Documentation}
 * @example
 * import { ListBox } from '@andes/listbox';
 * import { ListItem } from '@andes/list';
 *
 * const MyComponent = () => (
 *  <ListBox
 *    defaultSelectedKeys={['2']}
 *    selectionMode="single"
 *    id="selectable-example"
 *    srLabel="Selectable List"
 *  >
 *    <ListItem
 *      value="0"
 *      title="DHL Express"
 *      description="Arrives May 10th"
 *      rightContent="Free"
 *    />
 *    <ListItem
 *      value="1"
 *      title="DHL Express"
 *      description="Arrives May 12nd"
 *      disabled
 *    />
 *    <ListItem value="2" title="DHL Premium" />
 *  </ListBox>
 *);
 */
export const ListBox: FunctionComponent<ListBoxProps & ListProps>;
